// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check field 課名 -  default value', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check field 課名 -  default value', async function() {
    await driver.get("http://localhost:4200/admin-user/list-user");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-layout-content")).click();
    await driver.findElement(By.css(".ant-select-open .ant-select-selection-item")).click();
    await driver.findElement(By.css(".ant-select-selector:nth-child(2) > .ant-select-selection-item")).click();
    assert(await driver.findElement(By.css(".ant-select-focused .ant-select-selection-item")).getText() == "すべて");
  });
});
